import React from "react";

const ToTime = ({ handleChange, valueEnd }) => {
  return (
    <div className="toLabel">
      <label htmlFor="to">Pana la</label>
      <input
        type="time"
        id="toTime"
        name="to"
        required
        onChange={handleChange}
        value={valueEnd}
      />
    </div>
  );
};

export default ToTime;
