import {useState} from "react";
import WeekDays from "./components/WeekDays";
import Activity from "./components/Activity";
import Navigation from "./components/Navigation";
import Summary from "./components/Summary";

const App = () => {
  const weekDays = ["Luni", "Marti", "Miercuri", "Joi", "Vineri", "Rezumat"];

  const [count, setCount] = useState(0);
  const [morningActivity, setMorningActivity] = useState("Alergare Usoara");
  const [eveningActivity, setEveningActivity] = useState("Inot");
  const [startMorningTime, setStartMorningTime] = useState("09:00");
  const [endMorningTime, setEndMorningTime] = useState("11:00");
  const [startEveningTime, setStartEveningTime] = useState("19:00");
  const [endEveningTime, setEndEveningTime] = useState("21:00");

  const [summaryPrint, setSummaryPrint] = useState([]);

  const onChangeDays = (newCount, operation) => {
    if (operation === "next") {
      // create info per day
      const newEntry = {
        day: weekDays[count],
        morningActivity: morningActivity,
        eveningActivity: eveningActivity,
        startMorningTime: startMorningTime,
        endMorningTime: endMorningTime,
        startEveningTime: startEveningTime,
        endEveningTime: endEveningTime,
      };
      // add day to array based on count index/ this will
      // re-write every time go back and then next -> for modifications
      const newSummaryPrint = [...summaryPrint];
      newSummaryPrint[count] = newEntry;

      setSummaryPrint(newSummaryPrint);

      // reset initial values
      setMorningActivity("Alergare Usoara");
      setEveningActivity("Inot");
      setStartMorningTime("09:00");
      setEndMorningTime("11:00");
      setStartEveningTime("19:00");
      setEndEveningTime("21:00");
    }
    // increase/decrease counter
    setCount(newCount);
  };

  // TODO: 2. when changing the time, dont let the end value be <= than the start value (at leats one hour)

  return (
    <div className="container">
      <WeekDays count={count} weekDays={weekDays} />
      {count < 5 ? (
        <>
          <Activity
            timeOfTheDay={"Dimineata"}
            handleChangeStart={(e) => setStartMorningTime(e.target.value)}
            valueStart={startMorningTime}
            handleChangeEnd={(e) => setEndMorningTime(e.target.value)}
            valueEnd={endMorningTime}
            activity={morningActivity}
            onChangeValue={(e) => setMorningActivity(e.target.value)}
          />
          <Activity
            timeOfTheDay={"Seara"}
            handleChangeStart={(e) => setStartEveningTime(e.target.value)}
            valueStart={startEveningTime}
            handleChangeEnd={(e) => setEndEveningTime(e.target.value)}
            valueEnd={endEveningTime}
            activity={eveningActivity}
            onChangeValue={(e) => setEveningActivity(e.target.value)}
          />
        </>
      ) : (
        <Summary summaryPrint={summaryPrint} />
      )}
      <Navigation count={count} onChangeDays={onChangeDays} />
    </div>
  );
};

export default App;
