import React from "react";

const WeekDays = ({ count, weekDays }) => {
  return (
    <div className="weekDays ">
      {weekDays.map((day, index) => (
        <div
          className={`day ${count === index ? "selectedDay" : ""}`}
          key={index}
        >
          {day}
        </div>
      ))}
    </div>
  );
};

export default WeekDays;
