import React from "react";

const Navigation = ({ count, onChangeDays }) => {
  const back = () => {
    onChangeDays(count - 1, "back");
  };

  const next = () => {
    onChangeDays(count + 1, "next");
  };

  return (
    <div className="buttons">
      <button disabled={count === 0} onClick={back}>
        Previous
      </button>
      <button disabled={count === 5} onClick={next}>
        Next
      </button>
    </div>
  );
};

export default Navigation;
