import React from "react";

const Summary = ({ summaryPrint }) => {
  return (
    <div className="summaryContainer">
      {summaryPrint.map((day, index) => (
        <div className="summary" key={index}>
          <div className="summaryDay">{day.day}</div>
          <div className="morningSummary">
            {day.startMorningTime} - {day.endMorningTime} {day.morningActivity}
          </div>
          <div className="eveningSummary">
            {day.startEveningTime} - {day.endEveningTime} {day.eveningActivity}
          </div>
        </div>
      ))}
    </div>
  );
};

export default Summary;
