import Selection from "./Selection";
import FromTime from "./FromTime";
import ToTime from "./ToTime";

const Activity = ({
  timeOfTheDay,
  handleChangeStart,
  valueStart,
  handleChangeEnd,
  valueEnd,
  activity,
  onChangeValue,
}) => {
  return (
    <div className="activitySection">
      <Selection
        timeOfTheDay={timeOfTheDay}
        activity={activity}
        onChangeValue={onChangeValue}
      />
      <FromTime handleChange={handleChangeStart} valueStart={valueStart} />
      <ToTime handleChange={handleChangeEnd} valueEnd={valueEnd} />
    </div>
  );
};

export default Activity;
