import React from "react";

const Selection = ({ timeOfTheDay, activity, onChangeValue }) => {
  return (
    <div className="activityLabel">
      <div className="overText">{timeOfTheDay}</div>
      <label htmlFor="activity" className="activity">
        Activitate
      </label>
      <select
        name="selectActivity"
        id="selectActivity"
        onChange={onChangeValue}
        value={activity}
      >
        <option value="Alergare Usoara">Alergare Usoara</option>
        <option value="Karate">Karate</option>
        <option value="Tenis">Tenis</option>
        <option value="Inot">Inot</option>
        <option value="Fotbal">Fotbal</option>
        <option value="Handbal">Handbal</option>
        <option value="Volei">Volei</option>
      </select>
    </div>
  );
};

export default Selection;
