import React from "react";

const FromTime = ({ valueStart, handleChange }) => {
  return (
    <div className="fromLabel">
      <label htmlFor="from">De la</label>
      <input
        type="time"
        id="fromTime"
        name="from"
        required
        onChange={handleChange}
        value={valueStart}
      />
    </div>
  );
};

export default FromTime;
